import { createContext, useState, FC, ReactNode } from 'react';
import { User } from '../lib/types';
interface Ctx { user: User | null; login: (u: User) => void; logout: () => void; }
export const AuthContext = createContext<Ctx>({} as Ctx);
export const AuthProvider: FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(() => JSON.parse(localStorage.getItem('user') || 'null'));
  const login = (u: User) => { setUser(u); localStorage.setItem('user', JSON.stringify(u)); };
  const logout = () => { setUser(null); localStorage.removeItem('user'); };
  return <AuthContext.Provider value={{ user, login, logout }}>{children}</AuthContext.Provider>;
};

import { createContext, useEffect, useState, FC, ReactNode } from 'react';
import { Room } from '../lib/types';
import { rooms } from '../services/rooms';
interface Ctx { rooms: Room[]; loading: boolean; refresh: () => void; }
export const RoomsContext = createContext<Ctx>({} as Ctx);
export const RoomsProvider: FC<{ children: ReactNode }> = ({ children }) => {
  const [roomsList, setRooms] = useState<Room[]>([]);
  const [loading, setLoading] = useState(true);
  const fetchRooms = () => { setLoading(true); rooms.list().then(setRooms).finally(() => setLoading(false)); };
  useEffect(fetchRooms, []);
  return <RoomsContext.Provider value={{ rooms: roomsList, loading, refresh: fetchRooms }}>{children}</RoomsContext.Provider>;
};

import { createContext, useEffect, useState, FC, ReactNode } from 'react';
import { Reservation } from '../lib/types';
import { reservations } from '../services/reservations';
import { useAuth } from '../hooks/useAuth';
interface Ctx { list: Reservation[]; add: (r: Reservation) => void; refresh: () => void; }
export const ReservationsContext = createContext<Ctx>({} as Ctx);
export const ReservationsProvider: FC<{ children: ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [list, setList] = useState<Reservation[]>([]);
  const refresh = () => user && reservations.byUser(user.id).then(setList);
  const add = (r: Reservation) => setList(prev => [...prev, r]);
  useEffect(refresh, [user]);
  return <ReservationsContext.Provider value={{ list, add, refresh }}>{children}</ReservationsContext.Provider>;
};

