import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { MainLayout } from '../components/layout/MainLayout';
import { Room } from '../lib/types';
import { rooms } from '../services/rooms';
import { Button } from '../components/ui/Button';
import { useAuth } from '../hooks/useAuth';
import { reservations } from '../services/reservations';
import { useReservations } from '../hooks/useReservations';
export default function RoomDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { add } = useReservations();
  const [room, setRoom] = useState<Room | null>(null);
  const [loading, setLoading] = useState(true);
  useEffect(()=>{ rooms.detail(id!).then(r=>{ setRoom(r); setLoading(false); }); },[id]);
  const reserve = async () => {
    if(!user) return navigate('/login');
    const now = new Date().toISOString();
    const res = await reservations.create({ roomId:id!, userId:user.id, from: now, to: now });
    add(res); navigate('/reservations');
  };
  if(loading) return <MainLayout>Cargando...</MainLayout>;
  if(!room) return <MainLayout>No encontrado</MainLayout>;
  return (
    <MainLayout>
      <img src={room.img} alt={room.title} className='w-full h-60 object-cover rounded mb-4'/>
      <h1 className='text-2xl font-bold mb-2'>{room.title}</h1>
      <p className='mb-4'>{room.description || 'Sin descripción.'}</p>
      <p className='font-semibold mb-6'>${room.price} / noche</p>
      <Button onClick={reserve}>Reservar</Button>
    </MainLayout>
  );
}

